@namespace Lumeo
@implements IAsyncDisposable

@{
    // Refresh the count at render start (not only in OnParametersSet) so the
    // catch-up re-render triggered by late step registration — which runs
    // WITHOUT a parameter set — still hands children the correct TotalSteps.
    _stepCount = _steps.Count;
    var context = new StepperContext(
        ActiveStep,
        EventCallback.Factory.Create<int>(this, SetActiveStep),
        Orientation,
        Linear,
        _stepCount,
        this,
        _tablistId);
}

<div class="@CssClass" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @* Render ChildContent first (hidden) so StepperStep components register themselves *@
        <div style="display:none">@ChildContent</div>
    </CascadingValue>

    @* Header: step indicators *@
    @{
        // Resize refs array after ChildContent (hidden) has registered all steps.
        if (_stepButtonRefs.Length != _steps.Count)
            _stepButtonRefs = new ElementReference[_steps.Count];
    }
    <div role="tablist"
         id="@_tablistId"
         aria-orientation="@(Orientation == Lumeo.Orientation.Vertical ? "vertical" : "horizontal")"
         class="@HeaderCssClass">
        @for (int i = 0; i < _steps.Count; i++)
        {
            var idx = i;
            var step = _steps[idx];
            var isActive = idx == ActiveStep;
            var isCompleted = step.Completed || idx < ActiveStep;
            var isError = !step.IsStepValid() && idx < ActiveStep;
            <button type="button"
                    id="@StepTabId(idx)"
                    role="tab"
                    aria-selected="@isActive.ToString().ToLower()"
                    aria-current="@(isActive ? "step" : null)"
                    aria-disabled="@(CanClickStep(idx) ? null : "true")"
                    aria-controls="@_panelId"
                    tabindex="@(idx == _focusedTabIndex ? 0 : -1)"
                    class="@GetStepIndicatorClass(idx, isActive, isCompleted, isError)"
                    @ref="_stepButtonRefs[idx]"
                    @onclick="() => HandleStepClick(idx)"
                    @onkeydown="(e) => HandleStepKeyDown(e, idx)">
                @if (step.IconContent is not null && !isCompleted && !isError)
                {
                    @step.IconContent
                }
                else if (isError)
                {
                    <Blazicon Svg="Lucide.X" class="h-4 w-4" />
                }
                else if (isCompleted)
                {
                    <Blazicon Svg="Lucide.Check" class="h-4 w-4" />
                }
                else
                {
                    <span class="text-sm font-semibold">@(idx + 1)</span>
                }
            </button>
            @if (Orientation == Lumeo.Orientation.Horizontal)
            {
                <div class="@GetStepLabelClass(idx, isActive, isCompleted)">
                    <span class="text-sm font-medium">@step.Title</span>
                    @if (!string.IsNullOrEmpty(step.Description))
                    {
                        <span class="text-xs text-muted-foreground">@step.Description</span>
                    }
                    @if (step.Optional)
                    {
                        <span class="text-xs text-muted-foreground italic">@L["Stepper.Optional"]</span>
                    }
                </div>
                @if (idx < _steps.Count - 1)
                {
                    <div class="@GetConnectorClass(idx, isCompleted)"></div>
                }
            }
        }
    </div>

    @* Vertical: labels beside indicators *@
    @if (Orientation == Lumeo.Orientation.Vertical)
    {
        <div class="flex flex-col gap-0">
            @for (int i = 0; i < _steps.Count; i++)
            {
                var idx = i;
                var step = _steps[idx];
                var isActive = idx == ActiveStep;
                var isCompleted = step.Completed || idx < ActiveStep;
                <div class="flex flex-row items-start gap-3 @(idx < _steps.Count - 1 ? "pb-6" : "")">
                    <div class="flex flex-col items-center">
                        <div class="h-8 w-8 shrink-0"></div>
                        @if (idx < _steps.Count - 1)
                        {
                            <div class="w-px flex-1 min-h-[24px] @(isCompleted ? "bg-primary" : "bg-border")"></div>
                        }
                    </div>
                    <div class="pt-1 pb-2">
                        <p class="@GetVerticalTitleClass(idx, isActive, isCompleted)">@step.Title</p>
                        @if (!string.IsNullOrEmpty(step.Description))
                        {
                            <p class="text-xs text-muted-foreground">@step.Description</p>
                        }
                        @if (step.Optional)
                        {
                            <p class="text-xs text-muted-foreground italic">@L["Stepper.Optional"]</p>
                        }
                    </div>
                </div>
            }
        </div>
    }

    @* Step body panel *@
    @* aria-labelledby points at the active step's tab id so AT announces
       'panel — Step N: Title' when the panel receives focus. The
       relationship is dynamic (active step changes), so we read the
       currently-active step's id directly each render. *@
    <div id="@_panelId" role="tabpanel" aria-labelledby="@(ActiveStep >= 0 && ActiveStep < _steps.Count ? StepTabId(ActiveStep) : null)" class="mt-4">
        @* KeepMounted steps render inside a STABLE keyed wrapper whose
           visibility toggles — re-parenting the fragment between renders
           would recreate the DOM and lose input state, which is the whole
           point of KeepMounted. Non-KeepMounted steps keep the historical
           behavior (only the active one is rendered, unwrapped). *@
        @for (int i = 0; i < _steps.Count; i++)
        {
            var stepIdx = i;
            var bodyStep = _steps[stepIdx];
            var isActivePanel = stepIdx == ActiveStep;
            @if (bodyStep.KeepMounted)
            {
                @* #105: key on the step's STABLE identity, not the loop index. An
                   index key makes Blazor reuse a kept-mounted panel's DOM for a
                   DIFFERENT step after a remove/insert, dragging stale input
                   state to the wrong owner. The Guid is generated once per
                   StepperStep instance, so the panel fragment tracks its true
                   owner across reorders.
                   DEFERRED: the pure *physical* @key reorder-with-reuse leg —
                   asserting the kept-mounted DOM nodes are re-ordered (not just
                   re-keyed) to match a new markup order — needs a DOM-order JS
                   interop probe to observe sibling order, which is out of scope
                   for this batch (no new shared interop). Identity-keying here is
                   the correctness fix; physical sibling reordering is unchanged. *@
                <div @key="bodyStep.Id" style="@(isActivePanel ? null : "display:none")" aria-hidden="@(isActivePanel ? null : "true")">@bodyStep.ChildContent</div>
            }
            else if (isActivePanel)
            {
                @bodyStep.ChildContent
            }
        }
    </div>

    @* Footer: navigation buttons *@
    <div class="@FooterCssClass">
        <button type="button"
                disabled="@(ActiveStep == 0)"
                class="@GetNavButtonClass(ActiveStep == 0)"
                @onclick="GoBack">
            @(BackLabel ?? L["Stepper.Back"])
        </button>
        <div class="flex-1"></div>
        @if (ActiveStep == _steps.Count - 1)
        {
            <button type="button"
                    disabled="@(!CanAdvance())"
                    class="@GetNavButtonClass(!CanAdvance(), primary: true)"
                    @onclick="Finish">
                @(FinishLabel ?? L["Stepper.Finish"])
            </button>
        }
        else
        {
            <button type="button"
                    disabled="@(!CanAdvance())"
                    class="@GetNavButtonClass(!CanAdvance(), primary: true)"
                    @onclick="GoNext">
                @(NextLabel ?? L["Stepper.Next"])
            </button>
        }
    </div>
</div>

@inject ThemeService Theme
@inject Lumeo.Services.Localization.ILumeoLocalizer L
@inject IComponentInteropService Interop

@code {
    // A scoped <DirectionProvider> cascades its direction here; when present it
    // wins over the global ThemeService so a subtree can be RTL even if the app
    // is LTR (and vice versa). Null when no provider wraps this stepper — then
    // the ambient theme direction applies.
    [CascadingParameter(Name = "LumeoDirection")] private LayoutDirection? ScopedDirection { get; set; }
    private LayoutDirection EffectiveDirection => ScopedDirection ?? Theme.CurrentDirection;

    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int ActiveStep { get; set; }
    [Parameter] public EventCallback<int> ActiveStepChanged { get; set; }
    [Parameter] public Lumeo.Orientation Orientation { get; set; } = Lumeo.Orientation.Horizontal;
    [Parameter] public bool Linear { get; set; } = true;
    [Parameter] public bool AllowStepClick { get; set; }
    [Parameter] public EventCallback OnFinish { get; set; }
    /// <summary>Override the "Next" button label. When null, uses the localized <c>L["Stepper.Next"]</c>. (#245)</summary>
    [Parameter] public string? NextLabel { get; set; }
    /// <summary>Override the "Back" button label. When null, uses the localized <c>L["Stepper.Back"]</c>. (#245)</summary>
    [Parameter] public string? BackLabel { get; set; }
    /// <summary>Override the "Finish" button label. When null, uses the localized <c>L["Stepper.Finish"]</c>. (#245)</summary>
    [Parameter] public string? FinishLabel { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Internal step registry — populated by StepperStep on each render pass
    internal readonly List<StepperStep.StepRegistration> _steps = new();
    // Identity-keyed registration: a StepperStep's OnParametersSet can run
    // MORE than once per parent render (CascadingValue with IsFixed=false
    // notifies subscribers AND re-renders ChildContent), so registration must
    // be idempotent per child INSTANCE. The previous slot-index scheme
    // double-registered every step on re-renders (duplicated indicators).
    // Registration order of step instances. Reordering dynamic steps (e.g.
    // inserting before existing ones without @key) keeps first-registration
    // order, not markup order — Blazor doesn't re-run children's
    // OnParametersSet in document order when instances are reused, so render
    // timing can't reconstruct position reliably. Static and appended steps
    // (the overwhelmingly common case) are correct; document this limitation
    // rather than ship an order heuristic that's wrong in subtle ways. Use
    // @key on the steps if you reorder them dynamically.
    private readonly List<StepperStep> _stepOwners = new();
    private readonly Dictionary<StepperStep, StepperStep.StepRegistration> _stepData = new();
    internal int _stepCount;

    // ElementReferences for each step indicator button — sized in OnParametersSet
    // so @ref bindings in the render loop always find a valid slot.
    private ElementReference[] _stepButtonRefs = Array.Empty<ElementReference>();

    // Roving-tabindex focus pointer (#197). The WAI-ARIA tablist keeps EXACTLY one
    // tab in the page tab order (tabindex=0); arrow/Home/End move that single stop
    // WITHOUT changing selection. This tracks which tab currently owns the stop.
    // Initialized to ActiveStep and re-synced to ActiveStep whenever the active
    // step changes (see _prevActiveStep below). Focus != activation: aria-selected
    // and aria-current stay bound to ActiveStep, not to this.
    private int _focusedTabIndex;
    // Previous ActiveStep, so OnParametersSet can detect an external change and
    // pull the roving focus pointer back onto the (new) active tab.
    private int _prevActiveStep = -1;

    // Stable IDs for the tabpanel and per-step tab buttons so the panel
    // can reference the active step via aria-labelledby. Without these,
    // AT announces the tabpanel without context (just "tab panel" instead
    // of "Step 2: Billing details, tab panel").
    private readonly string _panelId = LumeoIds.New("stepper-panel");
    private readonly string _tabIdPrefix = LumeoIds.New("stepper-tab");
    private string StepTabId(int idx) => $"{_tabIdPrefix}-{idx}";

    // Stable id ALWAYS present on the role=tablist container, so the DOM-order
    // roving-nav probe (Interop.GetOrderedDescendantIds) has an anchor to query the
    // role=tab buttons from. Also surfaced on StepperContext.ContainerId so the
    // tablist is addressable from the cascading context (mirrors RadioGroup).
    private readonly string _tablistId = LumeoIds.New("stepper-tablist");

    internal void RegisterStep(StepperStep owner, StepperStep.StepRegistration step)
    {
        // Idempotent per child instance: repeated OnParametersSet calls only
        // refresh the registration data; order is first-registration order.
        if (!_stepData.ContainsKey(owner))
            _stepOwners.Add(owner);
        _stepData[owner] = step;
        RebuildSteps();
    }

    internal void UnregisterStep(StepperStep owner)
    {
        if (_stepData.Remove(owner))
        {
            _stepOwners.Remove(owner);
            RebuildSteps();
            // #104: removing a step shrinks the list. A removed step's Dispose
            // runs during the parent's child-diff, AFTER the parent's own
            // OnParametersSet for this render — so the clamp there would observe
            // the OLD count. Re-clamp here against the freshly-shrunk list so an
            // out-of-range ActiveStep is corrected (and pushed back) on this very
            // teardown, not deferred to a later parameter set that may never come.
            ClampActiveStep();
            // Deferred + guarded: disposal may happen while the whole Stepper
            // is being torn down, where a re-render request is invalid.
            try { _ = InvokeAsync(StateHasChanged); }
            catch (ObjectDisposedException) { }
            catch (InvalidOperationException) { }
        }
    }

    private void RebuildSteps()
    {
        _steps.Clear();
        foreach (var owner in _stepOwners)
            _steps.Add(_stepData[owner]);
    }

    protected override void OnAfterRender(bool firstRender)
    {
        // StepperStep children initialize/register AFTER this parent has
        // already built its frames (on the first render: from an empty list —
        // header/panel/footer were blank until an unrelated re-render; the
        // old test suite worked around it with a manual extra Render()).
        // _stepCount snapshots the count at render start, so a difference
        // here means registrations landed during this pass — catch up with
        // exactly one re-render AFTER the batch completed (doing it inside
        // RegisterStep would interleave renders between sibling inits).
        if (_steps.Count != _stepCount)
        {
            StateHasChanged();
        }
    }

    // Suppress the browser default (page/panel scroll) for the roving-focus
    // navigation keys HandleStepKeyDown consumes above. Without this, Home/End (and
    // the arrow keys) also scroll a scrollable ancestor while the roving focus moves
    // between step tabs — a long form with many steps is exactly where this bites
    // (Codex P2). Registered once against the stable _tablistId; the tablist is
    // always mounted (no open/close cycle like an overlay), so this fires only on
    // the component's first render and stays registered for its whole lifetime.
    private bool _pdRegistered;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        try
        {
            await Interop.RegisterPreventDefaultKeys(_tablistId, new[]
            {
                new Lumeo.Services.PreventDefaultKeyRule("ArrowDown"),
                new Lumeo.Services.PreventDefaultKeyRule("ArrowUp"),
                new Lumeo.Services.PreventDefaultKeyRule("ArrowLeft"),
                new Lumeo.Services.PreventDefaultKeyRule("ArrowRight"),
                new Lumeo.Services.PreventDefaultKeyRule("Home"),
                new Lumeo.Services.PreventDefaultKeyRule("End"),
            });
            _pdRegistered = true;
        }
        catch (Microsoft.JSInterop.JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered) return;
        try { await Interop.UnregisterPreventDefaultKeys(_tablistId); }
        catch (Microsoft.JSInterop.JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    protected override void OnParametersSet()
    {
        _stepCount = _steps.Count;

        // Ensure the refs array is always large enough for the current step count.
        if (_stepButtonRefs.Length != _steps.Count)
            _stepButtonRefs = new ElementReference[_steps.Count];

        ClampActiveStep();

        // #197: keep the roving focus pointer on the active tab whenever the
        // active step changes (external @bind update, click, or a clamp above).
        // Arrow/Home/End move _focusedTabIndex on their own between renders; we
        // only re-anchor it here on a genuine ActiveStep change so a focus rove
        // isn't yanked back on every unrelated re-render.
        if (ActiveStep != _prevActiveStep)
        {
            _focusedTabIndex = ActiveStep;
            _prevActiveStep = ActiveStep;
        }
    }

    // #104: when the step count shrinks (e.g. a conditionally-rendered step is
    // removed), an ActiveStep that pointed past the new last index would leave
    // the panel blank and the Next/Finish footer wedged. Clamp into the valid
    // range and push the corrected value back so @bind-ActiveStep parents stay
    // in sync. The push is guarded exactly like UnregisterStep because shrink
    // can be driven by a child disposing during teardown, where invoking the
    // callback / re-rendering is invalid.
    private void ClampActiveStep()
    {
        if (_steps.Count == 0) return;
        var clamped = Math.Clamp(ActiveStep, 0, _steps.Count - 1);
        if (clamped == ActiveStep) return;

        ActiveStep = clamped;
        // Keep the roving focus pointer valid too — it could otherwise dangle
        // past the shrunk button array. _prevActiveStep is synced so a later
        // OnParametersSet doesn't treat this as a fresh change and re-fire.
        _focusedTabIndex = clamped;
        _prevActiveStep = clamped;
        try { _ = ActiveStepChanged.InvokeAsync(clamped); }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    private bool CanAdvance()
    {
        if (ActiveStep >= _steps.Count) return false;
        var current = _steps[ActiveStep];
        return current.IsStepValid();
    }

    private bool CanClickStep(int idx)
    {
        if (!AllowStepClick) return false;
        if (!Linear) return true;
        // In linear mode: can only click steps that are completed or the next available
        return idx <= ActiveStep + (CanAdvance() ? 1 : 0);
    }

    private async Task HandleStepClick(int idx)
    {
        if (!CanClickStep(idx)) return;
        await SetActiveStep(idx);
    }

    // Arrow-key navigation between step indicator buttons (WAI-ARIA tab-list pattern).
    // ArrowUp: move focus to previous button. ArrowDown: next button.
    // ArrowLeft/Right: previous/next in LTR; swapped in RTL so keys follow visual flow.
    // Home/End: jump focus to the first/last tab (#196). All are focus-only — they
    // never change ActiveStep (use Enter/Space for activation).
    private async Task HandleStepKeyDown(KeyboardEventArgs e, int idx)
    {
        var isRtl = EffectiveDirection == LayoutDirection.Rtl;
        var (hBack, hForward) = isRtl ? ("ArrowRight", "ArrowLeft") : ("ArrowLeft", "ArrowRight");

        // Classify the key into a roving INTENT first and bail on an irrelevant key
        // BEFORE the async DOM-order probe (mirrors the RadioGroupItem template:
        // direction first, early-return, then await). intent: -1 prev, +1 next,
        // int.MinValue Home (first), int.MaxValue End (last).
        int intent = e.Key switch
        {
            _ when e.Key == hBack    || e.Key == "ArrowUp"   => -1,
            _ when e.Key == hForward || e.Key == "ArrowDown" => 1,
            "Home" => int.MinValue,                   // #196
            "End"  => int.MaxValue,                   // #196
            _ => 0
        };
        if (intent == 0) return;

        // Triage reorder leg: a keyed reorder MOVES reused step tab buttons to new
        // DOM positions WITHOUT rebuilding the C# _steps registry, so the integer
        // mount-order index goes stale. Resolve the neighbour from the LIVE DOM —
        // the probe returns the role=tab ids in document order; locate the focused
        // step's id in it, step there, then map the resolved id BACK to a _steps
        // index to rove/focus. Falls back to the registry-index logic on an
        // empty/NULL probe (prerender / JS off / unconfigured test double), so
        // existing behaviour is byte-for-byte unchanged.
        var domOrder = await OrderedTabIds();
        if (domOrder is { Length: > 0 })
        {
            var domIdx = System.Array.IndexOf(domOrder, StepTabId(idx));
            if (domIdx >= 0)
            {
                var targetDomIdx = intent switch
                {
                    int.MinValue => 0,
                    int.MaxValue => domOrder.Length - 1,
                    _ => domIdx + intent
                };
                if (targetDomIdx < 0 || targetDomIdx >= domOrder.Length) return;

                var targetStep = IndexOfStepId(domOrder[targetDomIdx]);
                if (targetStep < 0 || targetStep >= _stepButtonRefs.Length) return;

                // #197: move the single roving tab stop to the resolved step;
                // selection is untouched (focus != activation).
                _focusedTabIndex = targetStep;
                await _stepButtonRefs[targetStep].FocusAsync();
                return;
            }
            // The focused step's id is absent from the probe (stale) → fall through
            // to the registry-index logic below.
        }

        int target = intent switch
        {
            -1 => idx - 1,
            1 => idx + 1,
            int.MinValue => 0,                        // #196
            int.MaxValue => _stepButtonRefs.Length - 1, // #196
            _ => -1
        };

        // The existing bounds guard also covers Home/End (an empty tablist yields
        // End == -1, which is rejected here).
        if (target < 0 || target >= _stepButtonRefs.Length) return;

        // #197: move the single roving tab stop to the focus target so a
        // subsequent Shift+Tab leaves from the right place; selection is
        // untouched. Set BEFORE FocusAsync so the re-render that StateHasChanged
        // schedules emits the corrected tabindex.
        _focusedTabIndex = target;
        await _stepButtonRefs[target].FocusAsync();
    }

    // The role=tab ids in LIVE DOM order (document order). NOTE: a Loose-mode
    // JSInterop (the default test double) returns NULL for an unconfigured string[]
    // call — keep it nullable and null-guard at the call site, do NOT assume [].
    private async ValueTask<string[]?> OrderedTabIds()
    {
        try
        {
            return await Interop.GetOrderedDescendantIds(_tablistId, "[role='tab']");
        }
        catch (JSDisconnectedException) { return null; }
        catch (ObjectDisposedException) { return null; }
        catch (InvalidOperationException) { return null; } // JS unavailable (prerender)
    }

    // Map a tab id back to its index in the _steps registry. The tab ids are
    // generated as StepTabId(i), so compare directly rather than parsing the id
    // suffix (robust to the LumeoIds prefix format).
    private int IndexOfStepId(string id)
    {
        for (var i = 0; i < _steps.Count; i++)
            if (StepTabId(i) == id) return i;
        return -1;
    }

    private async Task GoNext()
    {
        if (!CanAdvance()) return;
        if (ActiveStep < _steps.Count - 1)
            await SetActiveStep(ActiveStep + 1);
    }

    private async Task GoBack()
    {
        if (ActiveStep > 0)
            await SetActiveStep(ActiveStep - 1);
    }

    private async Task Finish()
    {
        if (!CanAdvance()) return;
        await OnFinish.InvokeAsync();
    }

    private async Task SetActiveStep(int value)
    {
        ActiveStep = value;
        await ActiveStepChanged.InvokeAsync(value);
    }

    private string CssClass => Orientation == Lumeo.Orientation.Vertical
        ? Cx.Merge("flex flex-row gap-4", Class)
        : Cx.Merge("flex flex-col gap-0", Class);

    private string HeaderCssClass => Orientation == Lumeo.Orientation.Horizontal
        ? "flex flex-row items-center"
        : "flex flex-col items-center gap-0";

    private string FooterCssClass => "flex flex-row items-center gap-2 mt-6 pt-4 border-t border-border/40";

    private string GetStepIndicatorClass(int idx, bool isActive, bool isCompleted, bool isError)
    {
        var baseClasses = "flex h-8 w-8 shrink-0 items-center justify-center rounded-[calc(var(--radius)*2)] transition-colors p-1.5 -m-1.5 sm:p-0 sm:m-0";
        var stateClasses = isError
            ? "border-2 border-destructive bg-background text-destructive"
            : isCompleted
                ? "bg-primary text-primary-foreground"
                : isActive
                    ? "border-2 border-primary bg-background text-primary"
                    : "bg-muted text-muted-foreground";
        var cursorClasses = CanClickStep(idx)
            ? "cursor-pointer focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
            : "cursor-default";
        return $"{baseClasses} {stateClasses} {cursorClasses}";
    }

    private string GetStepLabelClass(int idx, bool isActive, bool isCompleted) =>
        "flex flex-col items-start mx-2";

    private string GetVerticalTitleClass(int idx, bool isActive, bool isCompleted) =>
        isActive
            ? "text-sm font-semibold text-foreground"
            : isCompleted
                ? "text-sm font-medium text-foreground"
                : "text-sm text-muted-foreground";

    private string GetConnectorClass(int idx, bool isCompleted) =>
        $"flex-1 h-px mx-2 {(isCompleted ? "bg-primary" : "bg-border/40")}";

    private string GetNavButtonClass(bool disabled, bool primary = false)
    {
        var baseClasses = "inline-flex items-center justify-center rounded-md px-4 py-2 text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2";
        var variantClasses = primary
            ? "bg-primary text-primary-foreground hover:bg-primary/90"
            : "border border-border/40 bg-background text-foreground hover:bg-muted/50";
        var disabledClasses = disabled ? "opacity-50 cursor-not-allowed pointer-events-none" : "cursor-pointer";
        return $"{baseClasses} {variantClasses} {disabledClasses}";
    }

    public record StepperContext(
        int ActiveStep,
        EventCallback<int> SetActiveStep,
        Lumeo.Orientation Orientation,
        bool Linear,
        int StepCount,
        Stepper Parent,
        // The role=tablist element id — the anchor for the DOM-order roving-nav probe
        // so arrow/Home/End tab order tracks the live DOM after a keyed reorder.
        string ContainerId);
}

@namespace Lumeo
@implements IDisposable

@* StepperStep registers itself into the parent Stepper's step list on each render.
   The actual rendering is done by Stepper using the registered data. Registration
   is keyed on this component instance (idempotent — OnParametersSet can fire more
   than once per parent render via the cascading-value double notification) and is
   withdrawn on dispose so conditionally-removed steps don't leave ghosts. *@

@code {
    // Stable identity generated ONCE per StepperStep instance. Threaded into the
    // registration so the KeepMounted panel wrapper can @key on the step's true
    // owner (#105) instead of its loop index — index keys make a reused panel
    // fragment track the WRONG owner across remove/insert, dragging stale input
    // state to a different step. A Guid is immutable for the instance lifetime,
    // so the keyed panel survives reorders without re-creating its DOM.
    private readonly Guid _id = Guid.NewGuid();

    [CascadingParameter] public Stepper.StepperContext? Context { get; set; }
    [Parameter] public string Title { get; set; } = "";
    [Parameter] public string? Description { get; set; }
    [Parameter] public bool Optional { get; set; }
    [Parameter] public bool Completed { get; set; }
    [Parameter] public Func<bool>? IsValid { get; set; }
    [Parameter] public RenderFragment? IconContent { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool KeepMounted { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    protected override void OnParametersSet()
    {
        Context?.Parent.RegisterStep(this, new StepRegistration(
            _id,
            Title,
            Description,
            Optional,
            Completed,
            IsValid,
            IconContent,
            ChildContent,
            KeepMounted));
    }

    public void Dispose()
    {
        Context?.Parent.UnregisterStep(this);
    }

    public bool IsStepValid() => IsValid?.Invoke() ?? true;

    public record StepRegistration(
        Guid Id,
        string Title,
        string? Description,
        bool Optional,
        bool Completed,
        Func<bool>? IsValid,
        RenderFragment? IconContent,
        RenderFragment? ChildContent,
        bool KeepMounted)
    {
        public bool IsStepValid() => IsValid?.Invoke() ?? true;
    }
}
